package org.eclipse.rdf4j.sail.lmdb.sketch;

import static org.junit.jupiter.api.Assertions.assertThrows;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.io.IOException;
import java.util.Arrays;

import org.junit.jupiter.api.Test;

class FrequencySketchSerializationTest {

	@Test
	void fastAgmsRejectsTrailingPayloadBytes() throws Exception {
		FastAgmsBindingSummary summary = new FastAgmsBindingSummary(3, 171, 0x51E7C0DEL);
		summary.update(1L, 3.0d);
		byte[] payload = withTrailingByte(summary.toByteArray());

		IOException failure = assertThrows(IOException.class, () -> FastAgmsBindingSummary.fromByteArray(payload));

		assertTrue(failure.getMessage().contains("trailing"));
	}

	private static byte[] withTrailingByte(byte[] payload) {
		byte[] copy = Arrays.copyOf(payload, payload.length + 1);
		copy[payload.length] = 1;
		return copy;
	}
}
